-- 경포해변 (contentid=128758)
UPDATE public.places SET description = '동해안 최대 해변으로 유명하며 강문동, 안현동에 있고 시내에서 북으로 6㎞, 경포대에서 1㎞ 되는 곳에 동해의 창파를 가득 담고 펼쳐진 명사오리(明沙五里)이다. 모두를 삼키기라도 하려는 듯 밀려오는 파도, 이를 쓸어안은 길이 1.8㎞, 면적 1.44㎢의 하얀 모래밭과, 시끄러운 일상을 조용히 차단하는 울창한 송림병풍의 조화가 해변 특유의 아름다움을 자아낸다. 경포대 해변은 백사장이 1.8㎞에 평균 수심이 1~2m로 적당한 깊이와 완만한 경사 때문에 해마다 많은 인파가 찾아오는 곳이다. 해변 주변에는 소나무 숲이 우거져 해수욕과 산림욕을 동시에 즐길 수 있어 피서지로 안성맞춤이다. 매년 여름마다 경포 해변 상설무대에서 여름밤 예술제가 열려 문화적인 볼거리도 다양하다. 경포호 주변에서 자전거를 대여하여 즐기는 하이킹 또한 하나의 명물이다. 또한, 주변에 설악산, 오대산 국립공원이 있어 산, 바다, 계곡 등을 두루두루 돌아볼 수 있다.', address = '강원특별자치도 강릉시 창해로 514 (안현동)', image_url = 'https://tong.visitkorea.or.kr/cms/resource/26/4075926_image2_1.jpg', api_content_id = '128758' WHERE name = '경포해변';

-- 경포대 (contentid=125790)
UPDATE public.places SET description = '강릉 경포대는 강릉을 대표하는 명승지 중 하나로, 국가지정문화재 보물 제2046호로 지정되어 있다. 고려시대의 문화를 보여주고 있는 관동팔경의 하나이며, 경포 호수 북쪽 언덕에 있는 누각이다. 고려 충숙왕 13년에 창건한 후 한차례 이건과 수차례 중수 기록이 대부분 자세히 남아있으며, 특히 창건 이전의 기록도 남아있어 시대별 변화과정을 구체적으로 확인할 수 있는 정자이다. 이름인 ‘경포대’ 전자체 현판은 유한지의 글씨이고, 해서체 현판은 이익회의 글씨이다. 경포대 내부에는 숙종의 직접 지은 ‘어제시’와 율곡 이이가 10세에 지었다는 ‘경포대부’를 비롯해, 조하망의 상량문 등 수많은 명사와 시인 묵객의 글이 게시되어 있다. 
누각 주위에는 소나무와 상수리나무들이 알맞게 우거져 운치 있는 경관을 이루고 있다. 경포 8 경과 경포월삼은 천하의 장관으로 전해져 오고 있다. 경포대 주변 관광지로는 오래된 소나무 숲과 벚나무가 어우러진 경포호가 위치하고 있으며, 경포호를 동해로부터 분리시키고 있는 해안사주는 경포해수욕장을 이루고 있다.', address = '강원특별자치도 강릉시 경포로 365 (저동)', image_url = 'https://tong.visitkorea.or.kr/cms/resource/46/3501446_image2_1.jpg', api_content_id = '125790' WHERE name = '경포대';

-- 안목해변 커피거리 (contentid=127722)
UPDATE public.places SET description = '강릉을 대표하는 해변 중 하나인 안목해변은 푸른 동해 바다와 향긋한 커피 향이 어우러진 특별한 명소이다. 
안목해변은 사계절 언제 찾아도 각기 다른 매력을 뽐내며 단순히 바다를 바라보는 것에 그치지 않고, 다채로운 먹거리와 즐길 거리, 그리고 편리한 인프라가 갖추어져 있어 완벽한 여행 코스를 제공한다. 유명한 커피거리는 물론 아름다운 바다를 배경으로 사진을 찍을 수 있어 관광객들이 많이 찾는 장소이다.', address = '강원특별자치도 강릉시 창해로14번길 20-1', image_url = 'https://tong.visitkorea.or.kr/cms/resource/57/4075957_image2_1.jpg', api_content_id = '127722' WHERE name = '안목해변 커피거리';

-- 오죽헌 (contentid=129784)
UPDATE public.places SET description = '조선시대의 대학자 율곡 이이와 관련하여 유명해진 강릉 지역의 대표적인 유적지인 오죽헌은 오죽헌과 강릉시립박물관으로 구분된다. 오죽헌은 조선초기의 건축물로 건축사적인 면에서 그 중요성을 인정받아 보물로 지정되었다. 이곳 오죽헌 몽룡실에서 율곡 이이가 태어났다. 경내에는 오죽헌을 비롯하여 문성사(文成祠), 사랑채, 어제각(御製閣), 율곡기념관 등이 있으며, 율곡기념관에는 사임당, 율곡, 매창, 옥산의 예술적 면모를 살펴볼 수 있는 유작들이 전시되어 있다. 1962년부터 현재까지 매년 율곡을 추모하는 대현 이율곡선생 제곡제를 봉행하고 있다. 시립박물관은 영동지방의 민속자료와 향토 유물을 수집·보관·연구·전시하며, 전통문화를 계승 발전시키고 사회교육 및 시민의 정서 함양에 기여하기 위한 취지로 설립되었다. 전시관은 영동지방에서 사용하던 생업도구와 의식주 관련 용품들이 전시된 향토민속관, 강릉지방에서 출토된 선사유물·불교유물·자기·전적·서화류가 전시된 역사문화관, 석조물과 영동지방의 묘제가 복원된 야외전시장으로 구분된다.', address = '강원특별자치도 강릉시 율곡로3139번길 24 (죽헌동)', image_url = 'https://tong.visitkorea.or.kr/cms/resource/39/3527139_image2_1.jpg', api_content_id = '129784' WHERE name = '오죽헌';

-- 강릉중앙시장 (contentid=132771)
UPDATE public.places SET description = '강릉 중앙시장은 강릉시 성남동 일대에 위치한 대표적인 전통시장으로, 1980년 1월 18일에 등록·개설되어 지금까지 활발히 운영되고 있다. 동쪽에는 동부시장, 서쪽에는 서부시장이 자리 잡고 있으며, 이 두 곳에 이어 세 번째로 개장된 시장으로서 강릉 시내 중심 유통 기능을 충실히 수행하고 있는 핵심 상권이다. 시장 주변에는 개별 상가들로 이루어진 성남시장이 인접해 있으며, 축협, 농협마트, 새마을금고 등의 기관이 밀집해 있어 지역 상권과 밀접하게 연결되어 있다. 특히 도로변과 골목길에는 다양한 노점이 형성되어 사계절 내내 지역 특산물이 활발히 거래되고 있어 전통 시장의 생동감을 느낄 수 있다. 중앙시장의 가장 큰 특징은 강릉 지역의 향토성을 고스란히 간직하고 있다는 점이다. 강릉 도심에 거주하는 시민은 물론, 동해안 인근의 농어촌 주민들까지 찾는 시장으로, 농수산물, 건어물, 강릉 특산 식재료 등 다양한 품목들이 오가며 지역 경제의 중심 역할을 해오고 있다. 특히 매년 열리는 강릉 단오제 기간에는 시장 주변 남대천 단오장 일대가 축제 분위기로 가득 차며, 전국 각지에서 다양한 상품과 사람들이 모여드는 영동권 중심의 전통 재래시장으로서 더욱 활기를 띤다. 전통과 현대가 어우러진 공간에서 강릉의 삶과 문화를 느껴보고 싶다면, 중앙시장은 놓쳐서는 안 될 여행지 중 하나다.', address = '강원특별자치도 강릉시 금성로 21 (성남동)', image_url = 'https://tong.visitkorea.or.kr/cms/resource/65/3495765_image2_1.jpg', api_content_id = '132771' WHERE name = '강릉중앙시장';

-- 주문진수산시장 (contentid=132774)
UPDATE public.places SET description = '강원도 강릉시에 위치한 주문진수산시장은 오징어잡이로 유명한 주문진항을 끼고 1936년부터 형성된 재래시장이다. 이 시장은 종합시장, 건어물시장, 회센터 등을 포함한 다양한 형태의 상가와 연계되어 있으며, 동해안의 어시장이자 국내외 관광객이 많이 찾는 전통시장이다. 동해안에서 갓 잡은 오징어를 비롯해 고등어, 명태, 꽁치, 게 등 신선한 수산물과 다양한 건어물을 취급하고 있으며, 시중가보다 저렴한 가격에 구입할 수 있다. 또한 동해의 정취가 묻어나는 싱싱한 회를 즉석에서 맛볼 수 있는 점도 큰 매력이다.', address = '강원특별자치도 강릉시 주문진읍 시장길 38', image_url = 'https://tong.visitkorea.or.kr/cms/resource/21/3500121_image2_1.jpg', api_content_id = '132774' WHERE name = '주문진수산시장';

-- 선교장 (contentid=125800)
UPDATE public.places SET description = '강릉 선교장은 강원도 지역에서 가장 잘 남아 있는 품위 있는 사대부 가옥이다. 강릉시에 경포 쪽으로 4km쯤 떨어진 선교장은 조선시대 상류층의 가옥을 대표하는 곳으로, 국가민속문화유산으로 지정되었다. 경포호가 지금보다 넓었을 때, 배 타고 건넌다라고 하여 이 동네를 배다리 마을(船橋里)이라 불렀는데, 선교장이란 이름은 바로 여기서 유래한다. 선교장은 조선 영조 때(1703년) 효령대군의 후손인 이내번이 족제비 떼를 쫓다가 우연히 발견한 명당자리에 집을 지은 후, 그 후손이 지금도 살고 있다. 긴 행랑에 둘러싸인 안채, 사랑채, 동별당, 가묘 등이 정연하게 남아있고, 문밖에는 수백 평의 연못 위에 세워진 활래정이라는 정자가 있어, 정원까지 갖춘 구조를 보여 준다. 선교장은 건물뿐 아니라 조선 후기의 주거생활과 생활용구를 연구하는데 귀중한 자료가 되고 있다.', address = '강원특별자치도 강릉시 운정길 63 (운정동)', image_url = 'https://tong.visitkorea.or.kr/cms/resource/64/3493164_image2_1.jpg', api_content_id = '125800' WHERE name = '선교장';

-- 강릉대도호부관아 (contentid=125788)
UPDATE public.places SET description = '강릉 임영관 삼문은 강원특별자치도 강릉시 용강동에 있는 문 중 하나로, 1962년에 국가유산으로 지정된 강릉의 자랑이자 명소로 자리 잡았다. 옛 명칭은 ‘강릉 객사문’이었는데, 2010년 4월부터 ‘임영관 삼 문’이라 부르게 되었다. 임영관 삼 문은 단층의 맞배지붕으로, 3칸 2호의 장중한 형태를 갖춘 우수한 팔각 문이다. 건립되었던 연대는 분명하지 않으나 그 건축 방식으로 보아서 조선 초기의 것으로 추정된다. 비록 규모는 작지만, 한국 목조 건축사상 뛰어난 구조와 아름다움을 갖추고 있는 선조들이 물려준 아름다운 유산이다.

(출처 : 강릉시 문화관광 홈페이지)', address = '강원특별자치도 강릉시 임영로131번길 6', image_url = 'https://tong.visitkorea.or.kr/cms/resource/26/3393426_image2_1.JPG', api_content_id = '125788' WHERE name = '강릉대도호부관아';

-- 하슬라아트월드 (contentid=127951)
UPDATE public.places SET description = '하슬라아트월드는 자연과 사람, 예술이 조화롭게 공존하는 종합예술공간이다. 3만 3천여 평의 조각공원은 ‘성성활엽길’, ‘소나무 정원’, ‘시간의 광장’, ‘바다정원’, ‘하늘전망대’, ‘돌갤러리와 소똥미술관’의 테마로 자연훼손을 최소화하기 위하여 비탈면과 산의 높이를 그대로 이용하여 손으로 직접 만들었으며 자연을 가장 아름답게 볼 수 있는 각도로 길을 내고 예술정원으로 꾸몄다. 하슬라아트월드는 국내외 작가들과 함께 하는 예술 작업 및 공연 전시 축제가 1년 내내 끊이지 않는 특별한 경험과 행복을 주는 공간이다. 실내미술관에는 현대 미술 200여 점이 전시된 ‘현대 미술관’과 유럽 각국에서 수집한 마리오네트와 피노키오 작품들이 전시된 ‘피노키오 & 마리오네트 미술관’이 있다. 하슬라 미술관은 기획전시, 초대전시, 상설전시가 진행 중이며 전시 스케줄에 따라 관람할 수 있다.

◎ 한류의 매력을 만나는 여행 정보 - 드라마  예리가 전 연인과의 추억을 정리하는 장면의 배경이 된 곳이다. CNN이 선정한 ‘강원의 추천 명소’로, 미술품을 감상하고 자연을 배경으로 인생 사진을 찍을 수 있는 인기 관광지다. 예리가 마음을 추슬렀던 야외 전시관에 서서 바다를 바라보면 탁 트인 풍경에 답답했던 마음이 뻥 뚫리는 기분이다.', address = '강원특별자치도 강릉시 강동면 율곡로 1441', image_url = 'https://tong.visitkorea.or.kr/cms/resource/17/2716617_image2_1.jpg', api_content_id = '127951' WHERE name = '하슬라아트월드';

-- 모래시계공원(정동진) (contentid=128721)
UPDATE public.places SET description = '모래시계공원은 동해 바다와 산, 정동진 2리 마을을 배경으로 아담하게 꾸며져 있다. 한가운데에는 모래시계가 있고, 그 주위에는 소나무가 있다. 그리고 바다 쪽으로는 벤치가 자리 잡고 있다. 모래시계공원 바로 앞은 정동진해수욕장과 이어져 있다. 
정동진 모래시계공원은 1999년 강릉시와 삼성전자가 새로운 천년을 기념하기 위해 조성했다. 공원 내 모래시계는 크기와 무게가 세계 최대이며, 시계 속에 있는 모래가 모두 아래로 떨어지는 데 걸리는 시간은 꼭 1년이 걸린다. 그러면 다음 해 1월 1일 0시에 반바퀴 돌려 위아래를 바꿔 새롭게 시작하게 된다. 정동진 모래시계는 허리가 잘록한 호리병박 모양의 유리그릇이 아니고 둥근 모양인 것은 시간의 무한성을 상징하기 위함이다. 또 둥근 것은 동해바다에서 떠오르는 태양을 상징하고, 평행선의 기차 레일은 영원한 시간의 흐름을 의미한다. 모래시계를 세운 정동진은 서울 광화문 앞에 있는 도로원표석을 기점으로 정동 쪽에 있는 고을이다. 그래서 하지 때는 한반도 제일 동쪽으로 해가 뜨는 고을이다.', address = '강원특별자치도 강릉시 강동면 헌화로 990-1', image_url = 'https://tong.visitkorea.or.kr/cms/resource/51/4075951_image2_1.jpg', api_content_id = '128721' WHERE name = '모래시계공원';

-- 강릉월화거리 (contentid=2588752)
UPDATE public.places SET description = '춘향전의 모티브이기도 한 이 ‘남대천 월화정 설화’는 ‘월화거리’로 재탄생되어 천년전 설화가 아닌 오늘을 살아가는 모든 사람들의 사랑 이야기로 다시 채워지고 있다. 사랑의 성지(聖地)로 다시 태어난 월화거리! 월화거리는 지금, 사랑이다. 남대천 월화정 설화는 남녀 간의 애틋한 사랑이야기로, 신라 시대 강릉 김씨의 시조가 된 명주군왕 김주원의 부모인 ‘무월랑’과 ‘연화 부인’이 그 주인공이다. 신라 진평왕시절 경주에서 강릉(옛지명·명주)으로 부임한 무월랑은 지방 토호의 딸인 연화를 우연히 만나 사랑에 빠지게 된다. 그러나 조정의 명으로 다시 경주로 떠난 후 무월랑은 연화를 잊게 되고, 부모님의 성화에 다른 이와 혼례를 치러야 하는 연화는 자주 가던 연못의 잉어에게 편지를 부탁하고 바다로 보낸다. 한 편, 어머니의 병환 때문에 장에 들렸던 무월랑은 잉어 한 마리를 사오게 되고, 잉어의 배를 가르니 편지가 나오는데 바로 연화의 편지였다. 무월랑은 급히 다시 강릉을 찾게 되고, 이 일이 사람의 힘이 아닌 정성에 하늘이 감동된 일임을 인정한 양쪽 부모에게 허락을 얻어 드디어 부부의 연을 맺게 된다.

(출처 : 디지털강릉문화대전)', address = '강원특별자치도 강릉시 금성로11번길 9', image_url = 'https://tong.visitkorea.or.kr/cms/resource/50/2921850_image2_1.jpg', api_content_id = '2588752' WHERE name = '강릉월화거리';

-- 월화거리야시장 (contentid=2588752)
UPDATE public.places SET description = '춘향전의 모티브이기도 한 이 ‘남대천 월화정 설화’는 ‘월화거리’로 재탄생되어 천년전 설화가 아닌 오늘을 살아가는 모든 사람들의 사랑 이야기로 다시 채워지고 있다. 사랑의 성지(聖地)로 다시 태어난 월화거리! 월화거리는 지금, 사랑이다. 남대천 월화정 설화는 남녀 간의 애틋한 사랑이야기로, 신라 시대 강릉 김씨의 시조가 된 명주군왕 김주원의 부모인 ‘무월랑’과 ‘연화 부인’이 그 주인공이다. 신라 진평왕시절 경주에서 강릉(옛지명·명주)으로 부임한 무월랑은 지방 토호의 딸인 연화를 우연히 만나 사랑에 빠지게 된다. 그러나 조정의 명으로 다시 경주로 떠난 후 무월랑은 연화를 잊게 되고, 부모님의 성화에 다른 이와 혼례를 치러야 하는 연화는 자주 가던 연못의 잉어에게 편지를 부탁하고 바다로 보낸다. 한 편, 어머니의 병환 때문에 장에 들렸던 무월랑은 잉어 한 마리를 사오게 되고, 잉어의 배를 가르니 편지가 나오는데 바로 연화의 편지였다. 무월랑은 급히 다시 강릉을 찾게 되고, 이 일이 사람의 힘이 아닌 정성에 하늘이 감동된 일임을 인정한 양쪽 부모에게 허락을 얻어 드디어 부부의 연을 맺게 된다.

(출처 : 디지털강릉문화대전)', address = '강원특별자치도 강릉시 금성로11번길 9', image_url = 'https://tong.visitkorea.or.kr/cms/resource/50/2921850_image2_1.jpg', api_content_id = '2588752' WHERE name = '월화거리야시장';

-- 송정해수욕장 (contentid=125694)
UPDATE public.places SET description = '송정동에 있으며 길이 700m, 2만8천㎡의 백사장이 있다. 주변에는 송림이 유명하다. 고려 충숙왕의 부마 최문한(崔文漢)이 송도에서 강릉에 올 때 소나무 8그루를 가지고 와 이곳에 심어 팔송정이라 하다가 그 후 송정이라 했다고 전하고 있다. 도로를 접한 입구에 쉴 수 있는 벤치와 간이매점이 있어 해수욕을 즐기는 이보다는 드라이브를 나온 사람들이 간단한 차 한잔이나 음료수로 바다를 관망하기 좋다. 소나무가 해변 도로 양 옆을 가득 메워 분위기 또한 최고이다.', address = '강원특별자치도 강릉시 창해로 118 (송정동)', image_url = 'https://tong.visitkorea.or.kr/cms/resource/28/2671428_image2_1.jpg', api_content_id = '125694' WHERE name = '송정해수욕장';

-- 풍호마을 (contentid=3069501)
UPDATE public.places SET description = '원래 연꽃은 7월 초에 피어나기 시작하는데, 강릉 연이랑 풍호마을은 감자작목반 수확으로 부득이하게 7월 말에 축제를 진행한다. 단풍나무가 많은 호수라 해서 이름 붙여진 풍호마을에서 열리는 연꽃 축제는 기찻길을 끼고 있는 풍경과 더불어 초록빛 자연 늪지에 만발한 연꽃으로 해마다 인기를 더하고 있다. 약 30만 평의 풍호마을에 피어난 연꽃들, 큼직한 연잎들이 푸른빛을 뽐내고 있다. 중간중간에 휴식을 취할 수 있는 정자가 있어 햇빛을 피하며 잠시 벤치에 앉아 바람에 흔들리는 연잎과 연꽃을 바라보며 꽃멍을 즐길 수 있다. 연꽃 축제에는 연꽃단지와 주변 습지에서 자라는 다양한 식물들을 감상할 수 있다. 연이랑 풍호마을 버스킹, 거북이 작가단, 퐁당퐁당 놀아줘 등 마을 분들이 만든 다양한 이벤트, 그리고 작품들을 만나볼 수 있다. 또한 연잎밥, 묵사발, 잔치국수, 연잎 돼지 수육, 도토리무침, 연잎 해물파전, 감자전 등 먹거리도 알차게 준비되어 있다.', address = '강원특별자치도 강릉시 강동면 하시동리 1300', image_url = 'https://tong.visitkorea.or.kr/cms/resource/25/3050625_image2_1.jpg', api_content_id = '3069501' WHERE name = '풍호마을';

-- 사천해변 (contentid=125696)
UPDATE public.places SET description = '사천 해변은 경포대 해변과 연곡 해변 사이에 있는 길이 300m, 18,000㎡의 매우 조용하고 깨끗함을 자랑하는 해변이다. 1975년 7월 1일 개장하였으며 경포도립공원과 인접해 있어 매년 많은 피서객이 찾고 있다. 해송숲이 넓게 우거져 있고 깨끗한 백사장과 얕은 수심으로 조용하게 피서를 즐기기 좋은 곳이다. 소나무 숲에서 풍겨 나오는 향긋한 냄새와 시원한 그늘은 깊은 추억을 만들기에 더욱 좋다. 안목해변 근처에 위치한 해변으로 여기는 사람들이 많이 몰리지 않아서 한적하고 조용한 바닷가로 이곳의 바다 색깔은 보석 에메랄드 빛을 띠고 있어 마치 외국의 어느 해안가에 와 있는 듯한 인상을 준다. 경포대가 젊은 연인들이 찾는 곳이라면 근처의 사천해수욕장은 물이 맑고 파도가 잔잔해서 스쿠버다이버, 낚시꾼, 가족단위 관광객이 찾는 곳이다. 계절별로 바다가 다른 색으로 옷을 바꿔 입기 때문에 사계절이 바뀔 때마다 계절을 만끽하러 오는 사람들이 많다. 또한 오토캠핑을 하기에 좋은 환경을 가지고 있어 사천해변은 오토캠핑 마니아들에게 천국처럼 여겨지는 곳이다. 오토 캠핑장은 향긋한 소나무 내음을 실컷 맡을 수 있는 안락한 캠핑장이다.', address = '강원특별자치도 강릉시 사천면 해안로 877', image_url = 'https://tong.visitkorea.or.kr/cms/resource/19/2922019_image2_1.jpg', api_content_id = '125696' WHERE name = '사천해변';

-- 솔향대게 (contentid=2685587)
UPDATE public.places SET description = '저렴한 가격에 러시아산 대게를 취급하는 곳이다. 강원도 강릉시에 있는 한식전문점이다. 대표메뉴는 대게다.', address = '강원특별자치도 강릉시 해안로 286', image_url = 'http://tong.visitkorea.or.kr/cms/resource/53/2684853_image2_1.jpg', api_content_id = '2685587' WHERE name = '솔향대게';

-- 초당순두부마을 (contentid=264370)
UPDATE public.places SET description = '강릉에서 가장 유명한 먹거리 중 하나인 초당순두부는 초당순두부는 콩을 갈아 여러 과정을 거쳐 동해안의 바닷물로 응고시켜 만든 것으로 굉장히 부드럽고 고소하다. 두부전골, 모두부, 짬뽕순두부 등 다양하고 이색적인 두부 요리를 맛볼 수 있다.
강릉 초당순두부마을의 이름은  한국의 유명한 소설가이자 시인이었던 허균과 그의 누나 난설헌의 아버지 허엽의 호를 따서 붙여진 이름이다. 강릉 초당순두부마을에는 허균허난설헌의 생가터가 남아있기도 하다. 이와 관련한 이야기가 있는데 허엽 선생이 강릉시 초당동에 살고 있으며, 집 앞에 있는 샘물의 맛이 좋아 그 물로 콩을 가공하여 깨끗한 바닷물로 간을 맞추어 두부를 만들었고, 그 맛이 좋다고 소문이 나기 시작하자 자신의 호인 초당을 붙여 마을 이름이 초당이 되었다고 한다. 
초당순두부마을은 순두부도 맛볼 수 있지만 초당두부가 생산되는 과정을 벽화로 쉽고 재미있게 볼 수 있다.', address = '강원특별자치도 강릉시 강문동 146-35', image_url = 'https://tong.visitkorea.or.kr/cms/resource/46/3378346_image2_1.JPG', api_content_id = '264370' WHERE name = '초당순두부마을';

-- 연곡해변 (contentid=125698)
UPDATE public.places SET description = '연곡면 동덕리에 있으며 길이 700m, 5만 6천㎡의 넓은 백사장을 간직하고 있다. 특히, 울창한 솔밭이 넓게 펼쳐져 있어 야영지로 최적이다. 소금강과 진고개에서 흘러 내려오는 맑은 연곡천에서 은어를 낚는 즐거움과 물장구치고 노는 개구쟁이들, 쪽대로 고기잡이하는 사람들의 모습을 많이 본다. 또 연곡천을 끼고 주변에는 먹거리촌들이 성시를 이룬다. 얼큰한 꾹저구탕, 맛깔스러운 토종닭, 산채백반, 막국수 등 푸짐한 먹을거리들이 사계절 메뉴를 바꾸어가며 식도락가들의 발길을 재촉한다. 동덕리에는 옛날 역이 있었고 연곡장도 섰다고 한다. 함경도와 경상도로 다니는 상선들이 드나들어 포구가 많이 발달되었다고 한다. 율곡 이이 선생이 산의 절경에 매료되어 아름다움을 극찬하여 쓰신 글 청학산기를 남긴 소금강이 가까운 거리에 있어 등산과 해수욕을 함께 즐길 수 있는 천혜의 피서 관광지이다. 하루 40대를 주차할 수 있는 1,000㎡의 간이 주차장과 13,220㎡의 소나무 숲에 하루 881곳의 텐트를 설치할 수 있는 야영장이 있다.', address = '강원특별자치도 강릉시 연곡면 해안로 1282', image_url = 'https://tong.visitkorea.or.kr/cms/resource/17/3016217_image2_1.jpg', api_content_id = '125698' WHERE name = '연곡해변';

-- 강문해변 (contentid=585522)
UPDATE public.places SET description = '강문해변은 강문동에 자리 잡고 있으며 주변에 작은 포구인 강문항이 있어 근처 횟집에서 새벽에 잡은 싱싱한 생선회를 맛볼 수 있다. 깨끗이 정비된 숙박시설과 경포지구가 근접해 있다. 강문해변에서는 보트로 5∼10분 걸리는 곳에 정박을 하여 수심 5∼30m의 바닷속에 방대하게 펼쳐진 자연짬(바위), 말미잘, 대형 어류 등 뛰어난 수중경관을 감상할 수 있어 스킨스쿠버 동호인들이 많이 찾고 있으며 특히 추억을 남기고 싶은 신혼부부를 위한 수중 다이빙도 하고 있다. 또한 강문항이 있어 16척의 어선이 가자미, 노래미, 문어, 민들조개(째복), 성게, 멍게, 해삼 등을 수시로 잡고 봄에는 넙치, 광어, 대복 조개, 여름과 가을에는 삼치, 겨울에는 우럭 등을 잡고 있다. 낚시 애호가들은 항구에서 황어와 노래미(놀래기) 등을 낚기도 한다.

◎ 한류의 매력을 만나는 여행 정보 - 드라마 
성준이 혜진과 바다를 보며 화보 촬영 아이디어를 떠올린 곳이다. 두 사람은 이곳에서 서로의 속마음을 드러내며 낭만적 기류를 형성하기도 했다. 동해를 배경으로 인생 사진을 찍을 수 있는 포토존이 많아 연인들의 데이트 코스로도 인기다.', address = '강원특별자치도 강릉시 창해로 352', image_url = 'https://tong.visitkorea.or.kr/cms/resource/79/2921979_image2_1.jpg', api_content_id = '585522' WHERE name = '강문해변';

-- 안반데기 (contentid=2714439)
UPDATE public.places SET description = '안반데기는 해발 1,100m 고산지대로, 떡메로 반죽을 칠 때 사용하는 오목하고 넓은 나무 받침인 ‘안반’과 평평한 땅을 뜻하는 ‘데기’에서 이름이 유래되었다. 1965년부터 화전민들이 산을 깎아 개간하며 정착하였고, 경사가 가팔라 기계농이 불가능해 전적으로 사람의 힘으로 밭을 일구었다. 1995년에는 28 가구 남짓의 주민들이 대를 이어 밭을 일구며 땅을 정식으로 매입하여 실질적인 소유주가 되었다. 약 200만㎡에 이르는 이 땅은 척박했던 산지를 풍요로운 고랭지 배추밭으로 탈바꿈시켰다. 단순한 배추밭을 넘어, 안반데기는 인간의 노동이 만든 경관으로 주목받고 있다.', address = '강원특별자치도 강릉시 왕산면 안반데기길 428', image_url = 'http://tong.visitkorea.or.kr/cms/resource/54/3537654_image2_1.jpg', api_content_id = '2714439' WHERE name = '안반데기';

-- 노추산 모정탑길 (contentid=1869883)
UPDATE public.places SET description = '강릉시 왕산면 대기리 노추산 자락에는 3,000개의 돌탑 골이 있다. 탑골을 만든 이는 차순옥 할머니로 2011년 향년 68세로 세상을 떠나기까지 무려 26년간 이곳에서 돌탑을 쌓았다. 
차순옥 할머니는 결혼한 후 4남매를 두었으나 아들 둘을 잃고 남편은 정신질환을 앓는 등 집안에 우환이 끊이질 않았다. 그렇게 40대 중년에 접어들던 어느 날, 할머니는 꿈에 나타난 산신령이 계곡에 돌탑 3,000개를 쌓으면 집안이 평안해질 것이라는 계시를 받았다. 강릉 시내에 살던 할머니는 이때부터 돌탑 쌓을 장소를 찾아다녔고, 1986년 ‘하늘 아래 첫 동네’로 통하는 대기리 노추산 계곡에 자리를 잡았고, 돌아가시기 전까지 이곳에서 돌탑을 쌓아왔다. 이후 TV 프로그램을 통해 입소문이 나면서 이곳은 모정탑길로 불리며 많은 관광객들이 방문하는 강릉의 관광명소로 거듭나고 있다.  
이곳엔 오토캠핑장도 함께 있는데 오토캠핑장 반대편 갈림길로 걸어가면 된다. 트래킹 코스는 약 1.2km가 되며 소요시간은 왕복 1~2시간 된다. 자식에 대한 사랑을 품은 노추산 모정돌탑공원에 소원 우체통이 마련되어 있으니 자식이 잘 되길 바라는 마음과 사랑하는 이를 위해 편지를 써보는 것도 좋을 것이다.', address = '강원특별자치도 강릉시 왕산면 대기리 1679-8', image_url = 'http://tong.visitkorea.or.kr/cms/resource/46/2050646_image2_1.jpg', api_content_id = '1869883' WHERE name = '노추산 모정탑길';

-- 굴산사지 당간지주 (contentid=125769)
UPDATE public.places SET description = '굴산사는 강릉 시내에서 남서쪽으로 6㎞ 정도 떨어져 있다. 범일국사가 신라 문성왕 9년(847년) 창건한 사찰로 신라의 불교 종파인 5교 9산 중 9본산의 하나였다. 굴산사가 폐사된 연대는 확실치 않으나 고려 말이나 조선 초기쯤으로 추정된다. 굴산사 일대는 현재 농경지로 변해 확실한 규모와 가람배치는 알 수 없으나 영동 지역 최대의 사찰로 전해지고 있다. 현재 이곳에는 굴산사지 당간지주(보물), 굴산사지 석불좌상(강원도 문화재자료) 등이 남아 있다. 범일국사 탄생 설화가 얽힌 학바위와 석천(石泉)이 있어 굴산사 당시의 규모를 짐작할 수 있다. 현재 이곳은 태풍 루사의 피해로 석천이 유실되었으며, 임시로 복구해 놓은 상태이다.', address = '강원특별자치도 강릉시 구정면 학산리', image_url = 'http://tong.visitkorea.or.kr/cms/resource/23/3025023_image2_1.jpg', api_content_id = '125769' WHERE name = '굴산사지 당간지주';

